import React, { useEffect, useState } from "react";
import API from "../../api/api";
import Sidebar from "../../components/Sidebar";
import { useNavigate } from "react-router-dom";

const ClientDashboard = () => {
  const navigate = useNavigate();

  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  // =========================================
  // FETCH CLIENT PROJECTS
  // =========================================
  const fetchProjects = async () => {
    try {
      const res = await API.get("/projects/client/my-projects");
      setProjects(res.data);
    } catch (err) {
      console.log("Error fetching projects:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProjects();
  }, []);

  // =========================================
  // CALCULATE STATS
  // =========================================
  const activeProjects = projects.filter(
    (p) => p.status !== "completed"
  );

  const completedProjects = projects.filter(
    (p) => p.status === "completed"
  );

  const totalSpent = completedProjects.reduce(
    (sum, p) => sum + Number(p.budget || 0),
    0
  );

  return (
    <div className="flex min-h-screen bg-gray-100">
      <Sidebar />

      <div className="flex-1 p-8">

        {/* HEADER */}
        <div className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-3xl font-bold">
              Client Dashboard
            </h2>
            <p className="text-gray-500">
              Manage your projects and freelancers
            </p>
          </div>

          <button
            onClick={() => navigate("/client/post-project")}
            className="bg-green-600 text-white px-6 py-3 rounded-lg hover:bg-green-700 transition"
          >
            + Post New Project
          </button>
        </div>

        {/* ===================== STATS CARDS ===================== */}
        <div className="grid md:grid-cols-4 gap-6 mb-10">
          <div className="bg-white p-6 rounded-xl shadow">
            <h4 className="text-gray-500">Active Projects</h4>
            <p className="text-3xl font-bold mt-2">
              {activeProjects.length}
            </p>
          </div>

          <div className="bg-white p-6 rounded-xl shadow">
            <h4 className="text-gray-500">Total Spent</h4>
            <p className="text-3xl font-bold mt-2 text-green-600">
              ₹{totalSpent}
            </p>
          </div>

          <div className="bg-white p-6 rounded-xl shadow">
            <h4 className="text-gray-500">Pending</h4>
            <p className="text-3xl font-bold mt-2 text-yellow-500">
              {activeProjects.length}
            </p>
          </div>

          <div className="bg-white p-6 rounded-xl shadow">
            <h4 className="text-gray-500">Completed</h4>
            <p className="text-3xl font-bold mt-2 text-blue-600">
              {completedProjects.length}
            </p>
          </div>
        </div>

        {/* ===================== RECENT PROJECTS ===================== */}
        <h3 className="text-xl font-semibold mb-6">
          Recent Projects
        </h3>

        {loading && <p>Loading projects...</p>}

        {!loading && projects.length === 0 && (
          <p className="text-gray-500">
            No Projects Found
          </p>
        )}

        {/* FULL WIDTH PROJECT LIST (UPDATED DESIGN) */}
        <div className="space-y-6">
          {projects.map((project) => (
            <div
              key={project.id}
              className="bg-white p-6 rounded-xl shadow hover:shadow-lg transition"
            >
              {/* Top Row */}
              <div className="flex justify-between items-start">
                <div>
                  <h3 className="text-xl font-semibold mb-2">
                    {project.title}
                  </h3>

                  <p className="text-gray-600 mb-4">
                    {project.description}
                  </p>
                </div>

                <span
                  className={`px-3 py-1 text-sm rounded-full ${
                    project.status === "completed"
                      ? "bg-green-100 text-green-600"
                      : "bg-blue-100 text-blue-600"
                  }`}
                >
                  {project.status || "open"}
                </span>
              </div>

              {/* Bottom Row */}
              <div className="flex justify-between items-center mt-4 text-sm text-gray-500">
                <div className="flex gap-6">
                  <span>
                    💰 ₹{project.budget}
                  </span>
                  <span>
                    📅 {project.deadline}
                  </span>
                </div>

                <span className="text-green-600 font-medium">
                  View Details →
                </span>
              </div>
            </div>
          ))}
        </div>

      </div>
    </div>
  );
};

export default ClientDashboard;
